function closeTask(DecisionToClose){
	new Task_uiAction().uiAction_UpdateTaskAndResponseLog(DecisionToClose, 'nonconcur_sign', current);
	// Redirect
	if (typeof spModal == 'undefined' ) {
		action.setRedirectURL (current) ;
	}
}

